import { readFile, readdir, writeFile } from 'node:fs/promises';
import { fileURLToPath } from 'node:url';
import path from 'node:path';

const root = path.dirname(path.dirname(fileURLToPath(import.meta.url)));
const supabaseDir = path.join(root, 'supabase');
const migrationsDir = path.join(supabaseDir, 'migrations');
const output = path.join(supabaseDir, 'bootstrap.generated.sql');

const migrations = (await readdir(migrationsDir))
  .filter((name) => /^\d{4}_[a-z0-9_]+\.sql$/.test(name))
  .sort((a, b) => a.localeCompare(b, 'en'));

const sections = [
  '-- GENERATED FILE. DO NOT EDIT OR RUN ON AN EXISTING DATABASE.',
  '-- Fresh-project bootstrap: schema.sql followed by every migration in filename order.',
  '-- Generated by: npm run db:bootstrap',
  '',
  '-- ===== BASE SCHEMA: schema.sql =====',
  await readFile(path.join(supabaseDir, 'schema.sql'), 'utf8'),
];

for (const name of migrations) {
  sections.push('', `-- ===== MIGRATION: ${name} =====`, await readFile(path.join(migrationsDir, name), 'utf8'));
}

await writeFile(output, `${sections.join('\n').trim()}\n`, 'utf8');
console.log(`Wrote ${path.relative(root, output)} (${migrations.length} migrations).`);
